mapper.select:
SELECT DISTINCT h.id, h.title, h.deadline, CASE WHEN hs.status = 2 THEN 2 WHEN hs.status = 1 THEN 1 WHEN h.deadline < NOW() THEN 3 ELSE 0 END AS status FROM homework h INNER JOIN homework_class hc ON h.id = hc.homework_id LEFT JOIN homework_submission hs ON h.id = hs.homework_id AND hs.student_id = #{studentId}
h.course_id = #{courseId} AND hc.course_class_id IN
#{classId}
AND h.status IN (1, 2) AND h.is_deleted = 0
ORDER BY h.deadline ASC
